/**
 * @fileoverview GridTable Feature — Filter mixin.
 *
 * Lazy-loaded when `showFilterRow: true` is set in config.
 * Adds column filtering (text, select/group, date) to the grid.
 *
 * @module module/GridTable/features/filter
 */

import {
    detectFilterType,
    collectColumnOptions,
} from '../helpers.js';

import {
    applyClientFilters,
    restoreFilterUI,
} from '../state.js';

import {
    buildFilterRow,
    buildFilterCell,
    autoDetectFilters,
    refreshFilterOptions,
} from '../view.js';

import {
    bindFilterEvents,
} from '../events.js';

import {
    reflowFilterRow as _reflowFilterRow,
} from '../layout.js';

/**
 * Install the filter feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installFilter(ctx) {
    // ── Build Filter UI ──
    buildFilterRow(ctx);
    bindFilterEvents(ctx);

    // ── Extend ctx with filter methods ──
    ctx._filterInstalled = true;

    ctx.buildFilterCell  = (name, filterType) => buildFilterCell(ctx, name, filterType);
    ctx.autoDetectFilters    = () => autoDetectFilters(ctx);
    ctx.refreshFilterOptions = () => refreshFilterOptions(ctx);
    ctx.applyClientFilters   = () => applyClientFilters(ctx);
    ctx.restoreFilterUI      = () => restoreFilterUI(ctx);
    ctx.reflowFilterRow      = () => _reflowFilterRow(ctx);

    // Initial reflow — the filter feature is lazy-loaded so the filter row
    // DOM is built *after* the first setData/reflowColumns call (which ran
    // with a no-op reflowFilterRow stub).  Position the cells now.
    _reflowFilterRow(ctx);
}

export default installFilter;
